registerInterfaceTranslations(copy)
const foldedOrbitCopy = new Map(Object.entries(copy).map(([key, value]) => [key.toLocaleLowerCase('en'), value]))

export function translateOrbit(value: string, language: IntroLanguage): string {
  if (language === 'en') return value
  return (copy[value] ?? foldedOrbitCopy.get(value.toLocaleLowerCase('en')))?.[language] ?? value
}

export function useOrbitText(): (value: string) => string {
  const { language } = useLanguage()
  return (value: string) => translateInterfaceText(value, language)
}

export const ORBIT_TRANSLATIONS = copy
